public static long solve(long[] nums, long k) {
    int n = nums.length;
    long[] prefixMod = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixMod[i + 1] = (prefixMod[i] + nums[i]) % k;
    }

    int[] modCounts = new int[(int) k];
    for (long mod : prefixMod) {
        modCounts[(int) mod]++;
    }

    long total = 0;
    for (long num : nums) {
        total += num;
    }

    for (int mod = 0; mod < k; mod++) {
        if (modCounts[mod] > 0) {
            total -= modCounts[mod] * mod;
        }
    }

    return total;
}
